import os, torch

def save_checkpoint_atomic(state, path):
    """Write checkpoint atomically to prevent corruption on crash."""
    tmp = path + '.tmp'
    try:
        torch.save(state, tmp)
        os.replace(tmp, path)   # atomic rename on POSIX; os.rename is not atomic on Windows
    except Exception:
        if os.path.exists(tmp):
            os.remove(tmp)
        raise
